import React, { createContext, useContext, useEffect, useState } from "react";
import { ListingContext } from "./ListingContext";

export const ValidationContext = createContext();

export const ValidationProvider = ({ children }) => {

const [autopilotError, setAutopilotError] = useState(false)

const {autopilot} = useContext(ListingContext)

// let validators = [model,year,trim,interior,exterior,autopilot,mileage,condition,title,location,price]

// let validation = [setModelError, setYearError,setTrimError,setInteriorError,setExteriorError,setAutopilotError,setMileageError,setCondition]

let validation = []

const validateForm = () => {
    if (autopilot.length === 0) {
        console.log('Autopilot not valid')
        setAutopilotError(true)
        validation.push(true)
    } else {
        setAutopilotError(false)
        validation.push(false)
    }
    // if (validation.includes(true)) {
    //     return false
    // } else {
    //     return true
    // }
}

useEffect(()=> {
    setAutopilotError(false)
},[autopilot])

    return (
        <ValidationContext.Provider value={{autopilotError, setAutopilotError, validateForm }}>
            {children}
        </ValidationContext.Provider>
    )
}
